scwin.btn_retrieve_onclick = async function (e) {
  scwin.g_chkScroll = false; // 처음부터 RowPositionChanged event를 태우지 않는다.

  var che = "1";
  if (ed_vehclNoCd.getValue() == "" && ed_odrNo.getValue() == "" && ed_cntrNo.getValue() == "" && acb_co_lc_transRsltsExistYn.getValue() == "") {
    $c.win.alert($p, "차량번호 또는 오더번호 또는 컨테이너번호 또는 출도착등록여부 중에 하나 이상의 조회조건을 선택하십시오.");
    return;
  }
  if ((ed_wrkDtFrom.getValue() == "" || ed_wrkDtTo.getValue() == "") && ed_vehclNoCd.getValue() != "" && ed_odrNo.getValue() == "" && ed_cntrNo.getValue() == "") {
    $c.gus.cfAlertMsg($p, "차량번호로 조회할 경우에는 작업계획일자를 입력해야합니다");
    return;
  }
  if ((ed_wrkDtFrom.getValue() == "" || ed_wrkDtTo.getValue() == "") && acb_co_lc_transRsltsExistYn.getValue() != "" && ed_vehclNoCd.getValue() == "" && ed_odrNo.getValue() == "" && ed_cntrNo.getValue() == "") {
    $c.gus.cfAlertMsg($p, "출도착등록여부로 조회할 경우에는 작업계획일자를 입력해야합니다");
    return;
  }

  // if(!cfIsAfterDate(ed_wrkDtFrom.getValue(), ed_wrkDtTo.getValue())) {
  // 	$c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자가 종료일자 이전이어야 합니다.
  // 	ed_wrkDtFrom.focus();
  // 	return;
  // }

  if (ed_wrkDtFrom.getValue() != "" && ed_wrkDtTo.getValue() != "" && $c.date.diffDate($p, ed_wrkDtFrom.getValue(), ed_wrkDtTo.getValue()) > 15) {
    $c.gus.cfAlertMsg($p, "조회기간은 14일 이내로 지정하여야 합니다.");
    return;
  }
  dma_retrieve.set("vehclNo", txt_vehclNoNm.getValue());
  dma_retrieve.set("wrkDt", ed_wrkDtFrom.getValue());
  dma_retrieve.set("wrkDtTo", ed_wrkDtTo.getValue());
  dma_retrieve.set("odrNo", ed_odrNo.getValue());
  dma_retrieve.set("transWrkIndictNo", scwin.transWrkIndictNo);
  dma_retrieve.set("cntrNo", ed_cntrNo.getValue());
  dma_retrieve.set("cheAll", che);
  dma_retrieve.set("transRsltsExistYn", acb_co_lc_transRsltsExistYn.getValue());
  dma_retrieve.set("wrkLobranCd", acb_co_lc_logisticsBranch.getValue());
  await scwin.submitExcute(sbm_retrieve);
};

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {
  let submitObj = $p.getComponentById(e.id);
  switch (submitObj) {
    case sbm_retrieve:
      await scwin.sbm_retrieve_submitdone(e);
      break;
    case sbm_batch:
      await scwin.sbm_batch_submitdone(e);
      break;
    case sbm_retrieve2:
      await scwin.sbm_retrieve2_submitdone(e);
      break;
    case sbm_chkContainer:
      await scwin.sbm_chkContainer_submitdone(e);
      break;
    case sbm_cntrNoSeqInfo:
      await scwin.sbm_cntrNoSeqInfo_submitdone(e);
      break;
    case sbm_saveEmp:
      await scwin.sbm_saveEmp_submitdone(e);
      break;
    default:
      break;
  }
};

// 다른 crud가 하나의 서브미션을 태울때 처리방법 (예. 업데이트, 삭제가 서브미션이 같을때) (예제화면: se_102_01_01b   bulk booking)
/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {
  const e = await $c.sbm.execute($p, sbmObj);
  if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await scwin.submitdone(e);
  }
  ;
};
