//-------------------------------------------------------------------------
// 출발일시 from ~ to 체크 함수
//-------------------------------------------------------------------------
scwin.f_DifferBetweenDate = function (sDateStr, eDateStr, dateFormat, row) {
  sDateStr = sDateStr.trim();
  eDateStr = eDateStr.trim();
  if (eDateStr == "00" || sDateStr == "00") {
    return true;
  }
  // 종료일자가 시작일자 이후인지 확인
  if (sDateStr >= eDateStr) {
    return false;
  }
  return true;
};

//-------------------------------------------------------------------------
// Row 간 일자 체크 함수
//-------------------------------------------------------------------------
scwin.f_RowDifferBetweenDate = async function () {
  var total_cnt = ds_emp2.getRowCount();
  var oldArvDt = "";
  var oldArvHh = "";
  var oldWrkStpCd = "";
  var j = 0;
  for (var i = 0; i < total_cnt; i++) {
    j = i - 1;
    if (i == 0) {
      if (ds_emp2.getCellData(i, "arvIoMgntYn") == 0) {
        oldArvDt = ds_emp2.getCellData(i, "arvDt");
        oldArvHh = ds_emp2.getCellData(i, "arvHh");
      } else if (ds_emp2.getCellData(i, "dptIoMgntYn") == 0) {
        oldArvDt = ds_emp2.getCellData(i, "dptDt");
        oldArvHh = ds_emp2.getCellData(i, "dptHh");
      } else {
        oldArvDt = "";
        oldArvHh = "";
      }
      oldWrkStpCd = ds_emp2.getCellData(i, "wrkStpCd");
      continue;
    }
    if (oldArvHh.trim() != "" && ds_emp2.getCellData(i, "dptHh").trim() != "") {
      if (ds_emp2.getRowStatusValue(i) == "1") {
        // asis : 3 -> tobe : 1
        if (ds_emp2.getCellData(i, "wrkStpCd") != DsConstants.WRK_STP_CD_SHUTTLE && ds_emp2.getCellData(i, "dptDt").trim() != "" && ds_emp2.getCellData(i, "dptHh").trim() != "" && oldArvDt.trim() != "" && oldArvHh.trim() != "" && ds_emp2.getCellData(i, "dptDt").trim() + ds_emp2.getCellData(i, "dptHh").trim() <= oldArvDt.trim() + oldArvHh.trim()) {
          $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타에서 시작일시가 " + j + "번째 종료일시보다  이후 이어야 합니다.");
          return true;
        }
      }
    } else {
      continue;
    }
    if (ds_emp2.getCellData(i, "arvIoMgntYn") == 0) {
      oldArvDt = ds_emp2.getCellData(i, "arvDt");
      oldArvHh = ds_emp2.getCellData(i, "arvHh");
    } else if (ds_emp2.getCellData(i, "dptIoMgntYn") == 0) {
      oldArvDt = ds_emp2.getCellData(i, "dptDt");
      oldArvHh = ds_emp2.getCellData(i, "dptHh");
    } else {
      oldArvDt = "";
      oldArvHh = "";
    }
  }
  return false;
};

